void solve(int CASE)
{
	string s; cin >> s;
	int n = s.size(); s = ' ' + s;
	s[1] = '(', s[n] = ')';
	var ns = s;

	var pre = vector<int>(n + 1);
	fa(i, 1, n) {
		if (ns[i] == '?')ns[i] = '(';
		pre[i] = pre[i - 1];
		if (ns[i] == '(')pre[i]++;
		else pre[i]--;
	}

	// 找距离最近的一对 ()
	// j => (
	int j = n + 1;
	if (pre[n])fb(i, n, 1)
		if (s[i] == '?' and ns[i] == '(') {
		ns[i] = ')';
		pre[n] -= 2;
		j = i;
		if (pre[n] == 0)break;
	}

	if (j > n) {
		cout << "YES" << endl;
		return;
	}

	// 合法序列构造完后的新前缀和
	fa(i, 1, n) {
		pre[i] = pre[i - 1];
		if (ns[i] == '(')pre[i]++;
		else pre[i]--;
	}

	// i => (
	int mn = pre[j - 1];
	fb(i, j - 1, 1) {
		mn = min(mn, pre[i]);
		if (s[i] == '?') {
			if (mn >= 2) {
				cout << "NO" << endl;
				return;
			}
			break;
		}
	}
	cout << "YES" << endl;
	return;
}
